B.OP=new A.hI("Pol\xedtica de Privacidade",null,B.Lr,null,null,null)
B.JQ=new A.hC(null,8,null,null)
B.lk=new A.ec(600)
B.Oq=new A.k(!0,B.z,null,null,null,null,20,B.lk,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.OM=new A.hI("EL Sistemas",null,B.Oq,null,null,null)
B.JP=new A.hC(null,4,null,null)
B.MQ=new A.k(!0,B.A,null,null,null,null,14,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.OO=new A.hI("\xdaltima atualiza\xe7\xe3o: 08 de julho de 2026",null,B.MQ,null,null,null)
B.R4=new A.dN("Esta Pol\xedtica de Privacidade aplica-se a todos os aplicativos desenvolvidos e publicados pela EL Sistemas na Google Play Store. A EL Sistemas \xe9 a entidade legal respons\xe1vel pelo desenvolvimento, publica\xe7\xe3o e manuten\xe7\xe3o desses aplicativos.",null)
B.QZ=new A.dN("Os usu\xe1rios que utilizam nossos servi\xe7os s\xe3o muito importantes para n\xf3s. Por isso, queremos que voc\xea saiba exatamente como tratamos suas informa\xe7\xf5es e como protegemos a sua privacidade. Reserve um tempo para conhecer nossas pr\xe1ticas e, em caso de d\xfavida, entre em contato conosco pelos canais informados ao final desta pol\xedtica.",null)
B.Rl=new A.fp("1. Quem somos",null)
B.R1=new A.dN("A EL Sistemas \xe9 uma empresa brasileira de desenvolvimento de software que oferece aplicativos e solu\xe7\xf5es de gest\xe3o. Esta pol\xedtica descreve as pr\xe1ticas de privacidade adotadas em todos os aplicativos publicados na Google Play Store sob o nome de desenvolvedor EL Sistemas.",null)
B.Rj=new A.fp("2. Informa\xe7\xf5es que coletamos",null)
B.QU=new A.dN("Nossos aplicativos foram projetados para funcionar sem a coleta de dados pessoais dos usu\xe1rios. A EL Sistemas n\xe3o coleta, armazena, compartilha ou divulga informa\xe7\xf5es pessoais que identifiquem o usu\xe1rio, tais como nome, endere\xe7o, telefone, e-mail pessoal, localiza\xe7\xe3o, fotos, contatos ou qualquer outro dado sens\xedvel do dispositivo.",null)
B.QY=new A.dN("Quando o aplicativo exige autentica\xe7\xe3o, as credenciais de acesso s\xe3o fornecidas pela empresa contratante dos nossos servi\xe7os e s\xe3o utilizadas exclusivamente para identificar o usu\xe1rio dentro do sistema de gest\xe3o, n\xe3o sendo utilizadas para qualquer outra finalidade.",null)
B.Rk=new A.fp("3. Como usamos as informa\xe7\xf5es",null)
B.QW=new A.dN("As informa\xe7\xf5es inseridas nos aplicativos s\xe3o utilizadas exclusivamente para a opera\xe7\xe3o das funcionalidades oferecidas, como o registro de dados de gest\xe3o da empresa contratante. N\xe3o utilizamos essas informa\xe7\xf5es para fins de publicidade, cria\xe7\xe3o de perfis ou venda a terceiros.",null)
B.Rn=new A.fp("4. Compartilhamento de dados",null)
B.R3=new A.dN("A EL Sistemas n\xe3o compartilha, vende, aluga ou divulga dados de usu\xe1rios a terceiros. Os dados operacionais trafegam apenas entre o aplicativo e os servidores da empresa contratante dos nossos servi\xe7os.",null)
B.Ri=new A.fp("5. Seguran\xe7a",null)
B.R_=new A.dN("Adotamos medidas t\xe9cnicas e organizacionais adequadas para proteger as informa\xe7\xf5es tratadas por nossos aplicativos contra acesso n\xe3o autorizado, altera\xe7\xe3o, divulga\xe7\xe3o ou destrui\xe7\xe3o.",null)
B.Rm=new A.fp("6. Privacidade de crian\xe7as",null)
B.R2=new A.dN("Nossos aplicativos s\xe3o destinados ao uso corporativo e n\xe3o s\xe3o direcionados a menores de 13 anos. N\xe3o coletamos intencionalmente informa\xe7\xf5es de crian\xe7as. Caso identifiquemos qualquer dado nesse sentido, ele ser\xe1 imediatamente exclu\xeddo.",null)
B.Ro=new A.fp("7. Direitos do usu\xe1rio (LGPD)",null)
B.QX=new A.dN("Em conformidade com a Lei Geral de Prote\xe7\xe3o de Dados (Lei n\xba 13.709/2018), o usu\xe1rio pode, a qualquer momento, solicitar informa\xe7\xf5es sobre o tratamento de seus dados, bem como sua corre\xe7\xe3o ou exclus\xe3o, por meio dos nossos canais de contato.",null)
